const WhatIsTENSContent = () => (
  <div className="space-y-5">
    <h3 className="text-lg font-semibold flex items-center gap-2" style={{ color: 'var(--ink)' }}>
      <Info className="h-5 w-5" style={{ color: 'var(--accent-hex)' }} />
      What is TENS Therapy?
    </h3>
    <p className="text-sm text-muted-foreground">
      <strong>Transcutaneous Electrical Nerve Stimulation (TENS)</strong> is a non-invasive, drug-free method of
      pain relief. A small, power bank-powered device delivers low-voltage electrical pulses through adhesive electrode
      pads placed on the skin over or near painful areas.
    </p>
    <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
      {[
        { emoji: '🔋', title: 'power bank-Powered',  body: 'Portable devices you can use at home or on the go.' },
        { emoji: '⚡', title: 'Electrical Pulses', body: 'Gentle currents that travel through the skin to nerves.' },
        { emoji: '💊', title: 'Drug-Free Relief',  body: 'No medications — works with your own nervous system.' },
      ].map(c => (
        <div key={c.title} className="p-4 rounded-xl border text-center" style={{ background: 'rgba(74,143,196,0.04)' }}>
          <div className="text-2xl mb-2">{c.emoji}</div>
          <p className="font-semibold text-sm" style={{ color: 'var(--ink)' }}>{c.title}</p>
          <p className="text-xs text-muted-foreground mt-1">{c.body}</p>
        </div>
      ))}
    </div>
    <div className="p-4 rounded-xl border" style={{ background: 'rgba(74,143,196,0.04)' }}>
      <h4 className="font-semibold text-sm mb-2" style={{ color: 'var(--ink)' }}>Conditions commonly managed with TENS</h4>
      <div className="flex flex-wrap gap-2">
        {['Chronic back pain', 'Osteoarthritis', 'Fibromyalgia', 'Post-surgical pain', 'Neck & shoulder tension', 'Knee pain', 'Neuropathy', 'Sciatica'].map(tag => (
          <span key={tag} className="text-xs px-2 py-1 rounded-full font-medium"
            style={{ background: 'rgba(2,132,199,0.1)', color: 'var(--accent-dark)' }}>{tag}</span>
        ))}
      </div>
    </div>
    <p className="text-xs text-muted-foreground italic">
      ⚠️ TENS provides <strong>temporary</strong> pain relief and varies by individual. It is not a cure. Always use under the guidance of a qualified healthcare professional.
    </p>
  </div>
);

