// ─────────────────────────────────────────────────────────────────────────────
// MAIN COMPONENT
// ─────────────────────────────────────────────────────────────────────────────
const EducationGuide = () => {
  const [activeTab, setActiveTab]           = useState<TopicKey>('what-is-tens');
  const [selectedRegion, setSelectedRegion] = useState<string | null>(null);
  const cardRefs = useRef<Record<string, HTMLDivElement | null>>({});
  const isMobile = useIsMobile();
  const [topic, setTopic]                   = useState<TopicKey | null>(null);

  const handleRegionClick = (id: string) => {
    setSelectedRegion(id);
    setTimeout(() => {
      const el = cardRefs.current[id];
      if (el) el.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }, 50);
  };

  const placementProps: PlacementContentProps = { selectedRegion, onRegionClick: handleRegionClick, cardRefs };

  const topicContentMap: Record<TopicKey, React.ReactNode> = {
    'what-is-tens':  <WhatIsTENSContent />,
    'app-purpose':   <AppPurposeContent />,
    'gate-control':  <GateControlContent />,
    'electrode':     <PlacementContent {...placementProps} />,
    'modes':         <ModesContent />,
    'pad-care':      <PadCareContent />,
    'safety':        <SafetyContent />,
    'doctor-export': <DoctorExportContent />,
  };

  // ── MOBILE ──────────────────────────────────────────────────────────────────
  if (isMobile) {
    if (topic !== null) {
      return (
        <div className="space-y-4">
          <button onClick={() => setTopic(null)} className="flex items-center gap-1 text-sm font-medium" style={{ color: 'var(--accent-dark)' }}>
            <ArrowLeft className="h-4 w-4" /> Learn
          </button>
          <div className="medical-card p-4">{topicContentMap[topic]}</div>
        </div>
      );
    }
    return (
      <div className="space-y-4">
        <h2 className="text-xl font-semibold" style={{ fontFamily: 'var(--font-display)', color: 'var(--ink)' }}>Learn</h2>
        <div className="space-y-3">
          {TOPICS.map(t => (
            <button key={t.key} onClick={() => setTopic(t.key)} className="w-full medical-card p-4 flex items-center gap-3 text-left">
              <div className="w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 icon-surface">
                <t.icon className="h-5 w-5" style={{ color: 'var(--accent-dark)' }} />
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold" style={{ color: 'var(--ink)' }}>{t.title}</p>
                <p className="text-xs" style={{ color: 'var(--ink-muted)' }}>{t.desc}</p>
              </div>
              <ChevronRight className="h-4 w-4 flex-shrink-0" style={{ color: 'var(--ink-subtle)' }} />
            </button>
          ))}
        </div>
      </div>
    );
  }

  // ── DESKTOP ─────────────────────────────────────────────────────────────────
  const tabs: { id: TopicKey; label: string }[] = [
    { id: 'what-is-tens',  label: '💡 What is TENS?'  },
    { id: 'app-purpose',   label: '❤️ App Purpose'    },
    { id: 'gate-control',  label: '⚡ Gate Control'   },
    { id: 'electrode',     label: '📍 Placement'      },
    { id: 'modes',         label: '🔄 Modes'          },
    { id: 'pad-care',      label: '🩹 Pad Care'       },
    { id: 'safety',        label: '🛡️ Safety'         },
    { id: 'doctor-export', label: '📤 Doctor Export'  },
  ];

  return (
    <Card className="w-full max-w-4xl mx-auto">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <BookOpen className="h-5 w-5" style={{ color: 'var(--accent-hex)' }} />
          TensPilot+ Education Centre
        </CardTitle>
      </CardHeader>
      <CardContent>
        {/* Scrollable tab bar */}
        <div className="flex border-b border-border mb-6 overflow-x-auto pb-px" style={{ scrollbarWidth: 'none' }}>
          {tabs.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`px-3 py-2 text-xs sm:text-sm font-medium border-b-2 -mb-px transition-colors whitespace-nowrap flex-shrink-0 ${
                activeTab === tab.id ? 'font-semibold' : 'border-transparent text-muted-foreground hover:text-foreground hover:border-border'
              }`}
              style={activeTab === tab.id ? { borderColor: 'var(--accent-hex)', color: 'var(--accent-dark)' } : {}}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* Active content */}
        {topicContentMap[activeTab]}

        {/* Footer CTA */}
        <div className="mt-8 flex flex-wrap gap-3 justify-center">
          <Button asChild className="btn-primary"><Link to="/session-setup">Setup a Session</Link></Button>
          <Button asChild variant="outline" className="btn-outline-ice"><Link to="/dashboard">View Dashboard</Link></Button>
        </div>
      </CardContent>
    </Card>
  );
};

export default EducationGuide;
